const rawSessionId = $input.item.json.sessionId || $input.item.json.chatSessionId || $input.item.json.sessionID || 'default';
const sessionId = String(rawSessionId).trim().slice(0, 120) || 'default';
const chatInput = String($input.item.json.chatInput || $input.item.json.message || '').trim();
const now = new Date().toISOString();

return {
  json: {
    sessionId,
    chatInput,
    now
  }
};

return {
  json: {
    ...$input.item.json,
    stage: 'auth',
    output: 'Hi, can you please provide your user ID and 4-digit PIN to continue?'
  }
};

const chatInput = String($input.item.json.chatInput || '').trim();
const session = $input.item.json;

const users = {
  '5673': { name: 'Devin', pin: '1234' },
  '8421': { name: 'Sarah', pin: '5678' },
  '3019': { name: 'Alex', pin: '9012' },
  '7745': { name: 'Jordan', pin: '3456' },
  '1298': { name: 'Maya', pin: '7890' }
};

function extractCredentials(input) {
  const idMatch = input.match(/(?:user\s*)?id\s*[:\-\s]?\s*(\d{4})\b/i);
  const pinMatch = input.match(/pin\s*[:\-\s]?\s*(\d{4})\b/i);
  if (idMatch && pinMatch) {
    return { userId: idMatch[1], pin: pinMatch[1], complete: true };
  }

  const numbers = input.match(/\b\d{4}\b/g) || [];
  if (numbers.length === 2) {
    return { userId: numbers[0], pin: numbers[1], complete: true };
  }

  return { userId: null, pin: null, complete: false };
}

const creds = extractCredentials(chatInput);
let authenticated = false;
let userName = session.userName || null;
let userId = session.userId || null;
let authAttempts = Number(session.authAttempts || 0);
let authError = null;
let nextStage = session.stage;

if (!creds.complete) {
  authError = 'missing_or_malformed_credentials';
} else {
  const user = users[creds.userId];
  if (user && user.pin === creds.pin) {
    authenticated = true;
    userName = user.name;
    userId = creds.userId;
    authAttempts = 0;
    nextStage = 'ready';
  } else {
    authError = 'invalid_credentials';
    authAttempts += 1;
    if (authAttempts >= 3) {
      nextStage = 'locked';
    }
  }
}

return {
  json: {
    sessionId: session.sessionId,
    chatInput,
    stage: nextStage,
    authenticated,
    userName: authenticated ? userName : null,
    userId: authenticated ? userId : null,
    authAttempts,
    authError,
    locked: nextStage === 'locked'
  }
};

const userName = $input.item.json.userName;

return {
  json: {
    output: 'Hi ' + userName + ', how can I help you today?'
  }
};

const attempts = $input.item.json.authAttempts;
const authError = $input.item.json.authError;

if (attempts >= 3) {
  return {
    json: {
      output: 'Maximum authentication attempts reached. Please try again later. Goodbye.'
    }
  };
}

if (authError === 'missing_or_malformed_credentials') {
  return {
    json: {
      output: 'Please enter both your user ID and a 4-digit numeric PIN.'
    }
  };
}

return {
  json: {
    output: 'Authentication failed. Please check your user ID and PIN, and try again.'
  }
};

return {
  json: {
    output: 'Your session has been locked due to too many failed attempts. Goodbye.'
  }
};

const query = String($input.item.json.query || '').toLowerCase().trim();
const baseDateInput = $input.item.json.baseDate;
const timezone = String($input.item.json.timezone || 'Asia/Kolkata');
const now = baseDateInput ? new Date(baseDateInput + 'T12:00:00') : new Date();

function addDays(date, days) {
  const d = new Date(date);
  d.setDate(d.getDate() + days);
  return d;
}

function addHours(date, hours) {
  const d = new Date(date);
  d.setHours(d.getHours() + hours);
  return d;
}

function addMinutes(date, minutes) {
  const d = new Date(date);
  d.setMinutes(d.getMinutes() + minutes);
  return d;
}

function getNextDayOfWeek(dayIndex) {
  const d = new Date(now);
  const current = d.getDay();
  let diff = dayIndex - current;
  if (diff <= 0) diff += 7;
  d.setDate(d.getDate() + diff);
  return d;
}

function getLastDayOfWeek(dayIndex) {
  const d = new Date(now);
  const current = d.getDay();
  let diff = current - dayIndex;
  if (diff <= 0) diff += 7;
  d.setDate(d.getDate() - diff);
  return d;
}

function isoDate(date) {
  return date.toISOString().slice(0, 10);
}

function fmtDate(date) {
  return new Intl.DateTimeFormat('en-GB', {
    weekday: 'long', day: 'numeric', month: 'long', year: 'numeric', timeZone: timezone
  }).format(date);
}

function fmtTime(date) {
  return new Intl.DateTimeFormat('en-US', {
    hour: 'numeric', minute: '2-digit', hour12: true, timeZone: timezone
  }).format(date);
}

function fmtFull(date) {
  return fmtDate(date) + ' at ' + fmtTime(date);
}

const dayMap = {
  sunday: 0, monday: 1, tuesday: 2, wednesday: 3,
  thursday: 4, friday: 5, saturday: 6
};

let resultDate = null;
let result = null;
let resultType = 'date';

if (!query) {
  return JSON.stringify({ success: false, intentType: 'date_time', error: 'missing_query' });
}

if (query === 'today' || query === 'what day is today' || query === 'current date') {
  resultDate = now;
  result = fmtDate(now);
} else if (query === 'now' || query === 'current time' || query === 'what time is it') {
  resultDate = now;
  result = fmtFull(now);
  resultType = 'date_time';
} else if (query === 'tomorrow') {
  resultDate = addDays(now, 1);
  result = fmtDate(resultDate);
} else if (query === 'yesterday') {
  resultDate = addDays(now, -1);
  result = fmtDate(resultDate);
} else if (query === 'day after tomorrow') {
  resultDate = addDays(now, 2);
  result = fmtDate(resultDate);
}

if (!result) {
  for (const [dayName, dayIndex] of Object.entries(dayMap)) {
    if (query.includes('next ' + dayName) || query.includes('coming ' + dayName) || query.includes('this coming ' + dayName) || query === dayName) {
      resultDate = getNextDayOfWeek(dayIndex);
      result = fmtDate(resultDate);
      break;
    }
    if (query.includes('last ' + dayName) || query.includes('previous ' + dayName) || query.includes('past ' + dayName)) {
      resultDate = getLastDayOfWeek(dayIndex);
      result = fmtDate(resultDate);
      break;
    }
  }
}

if (!result) {
  const fromNow = query.match(/(\d+)\s+(hour|minute|day|week|month)s?\s+(from now|later|ahead|from today)/);
  if (fromNow) {
    const n = parseInt(fromNow[1], 10);
    const unit = fromNow[2];
    switch (unit) {
      case 'hour': resultDate = addHours(now, n); result = fmtFull(resultDate); resultType = 'date_time'; break;
      case 'minute': resultDate = addMinutes(now, n); result = fmtFull(resultDate); resultType = 'date_time'; break;
      case 'day': resultDate = addDays(now, n); result = fmtDate(resultDate); break;
      case 'week': resultDate = addDays(now, n * 7); result = fmtDate(resultDate); break;
      case 'month': resultDate = new Date(now); resultDate.setMonth(resultDate.getMonth() + n); result = fmtDate(resultDate); break;
    }
  }
}

if (!result) {
  const ago = query.match(/(\d+)\s+(hour|minute|day|week|month)s?\s+ago/);
  if (ago) {
    const n = parseInt(ago[1], 10);
    const unit = ago[2];
    switch (unit) {
      case 'hour': resultDate = addHours(now, -n); result = fmtFull(resultDate); resultType = 'date_time'; break;
      case 'minute': resultDate = addMinutes(now, -n); result = fmtFull(resultDate); resultType = 'date_time'; break;
      case 'day': resultDate = addDays(now, -n); result = fmtDate(resultDate); break;
      case 'week': resultDate = addDays(now, -n * 7); result = fmtDate(resultDate); break;
      case 'month': resultDate = new Date(now); resultDate.setMonth(resultDate.getMonth() - n); result = fmtDate(resultDate); break;
    }
  }
}

if (!result) {
  return JSON.stringify({
    success: false,
    intentType: 'date_time',
    error: 'unsupported_query',
    supported: ['today', 'tomorrow', 'yesterday', 'next/last weekday', 'N hours/days/weeks from now', 'N hours/days/weeks ago']
  });
}

return JSON.stringify({
  success: true,
  intentType: 'date_time',
  query,
  result,
  resultType,
  isoDate: resultDate ? isoDate(resultDate) : null,
  timezone
});

const input = $input.item.json || {};
let rawAction = String(input.action || input.operation || input.command || '').trim().toLowerCase();
rawAction = rawAction.replace(/[\s-]+/g, '_');
const actionAliases = {
  add: 'save',
  create: 'save',
  save_intent: 'save',
  save_intents: 'save',
  set: 'save',
  next: 'get_next',
  get: 'get_next',
  fetch: 'get_next',
  fetch_next: 'get_next',
  pop: 'get_next',
  done: 'mark_done',
  complete: 'mark_done',
  completed: 'mark_done',
  mark_complete: 'mark_done',
  mark_completed: 'mark_done'
};
let action = actionAliases[rawAction] || rawAction;
const sessionId = String(input.sessionId || input.session_id || 'default');

function parseMaybeJson(value, fallback) {
  if (typeof value !== 'string') return value === undefined ? fallback : value;
  const trimmed = value.trim();
  if (!trimmed) return fallback;
  try {
    return JSON.parse(trimmed);
  } catch (error) {
    return value;
  }
}

function parseQueue(value) {
  const parsed = parseMaybeJson(value, value);
  return Array.isArray(parsed) ? parsed : [];
}

function parseParams(value) {
  const parsed = parseMaybeJson(value, value);
  return parsed && typeof parsed === 'object' && !Array.isArray(parsed) ? parsed : {};
}

function normalizeIntent(intent, index) {
  const parsed = parseMaybeJson(intent, intent);

  if (typeof parsed === 'string') {
    const lower = parsed.toLowerCase();
    const type = lower.includes('currency') || /\b[A-Z]{3}\b/i.test(parsed) ? 'currency_conversion'
      : lower.includes('date') || lower.includes('time') || lower.includes('tomorrow') || lower.includes('sunday') ? 'date_time'
      : 'unknown';
    return {
      id: 'intent-' + Date.now() + '-' + index,
      type,
      description: parsed,
      params: {},
      status: 'pending'
    };
  }

  const obj = parsed && typeof parsed === 'object' ? parsed : {};
  const type = String(obj.type || input.type || '').trim() || 'unknown';
  const description = String(obj.description || obj.name || input.description || type || 'intent').trim();
  return {
    id: String(obj.id || ('intent-' + Date.now() + '-' + index)),
    type,
    description,
    params: parseParams(obj.params || input.params || {}),
    status: obj.status || 'pending',
    result: obj.result || null,
    error: obj.error || null
  };
}

function canonical(intent) {
  return JSON.stringify({ type: intent.type, description: intent.description, params: intent.params });
}

function queueFromInput() {
  return parseQueue(input.queue || input.intentQueue || input.intentsQueue);
}

function intentsFromInput() {
  const candidates = [input.intents, input.intent, input.intentList, input.intent_list];
  for (const candidate of candidates) {
    const parsed = parseMaybeJson(candidate, undefined);
    if (Array.isArray(parsed)) return parsed;
    if (parsed !== undefined && parsed !== null && parsed !== '') return [parsed];
  }

  if (input.type || input.description || input.params) {
    return [{ type: input.type, description: input.description, params: input.params || {} }];
  }

  // Last-resort compatibility for LLM tool calls that send named fields only.
  if (input.from_currency || input.to_currency || input.amount || input.date) {
    return [{
      type: 'currency_conversion',
      description: [input.amount || 1, input.from_currency, 'to', input.to_currency, input.date || 'latest'].filter(Boolean).join(' '),
      params: {
        amount: input.amount || 1,
        from_currency: input.from_currency,
        to_currency: input.to_currency,
        date: input.date || 'latest'
      }
    }];
  }

  if (input.query) {
    return [{ type: 'date_time', description: String(input.query), params: { query: input.query } }];
  }

  return [];
}

if (!action) {
  if (intentsFromInput().length > 0) action = 'save';
  else if (queueFromInput().length > 0) action = 'get_next';
}

switch (action) {
  case 'save': {
    const newIntents = intentsFromInput();
    const seen = new Set();
    const queue = [];
    newIntents.map(normalizeIntent).forEach(function(intent) {
      const key = canonical(intent);
      if (!seen.has(key)) {
        seen.add(key);
        queue.push(intent);
      }
    });

    if (queue.length === 0) {
      return JSON.stringify({
        success: false,
        sessionId,
        error: 'no_intents_provided',
        saved: 0,
        queue: []
      });
    }

    return JSON.stringify({
      success: true,
      sessionId,
      saved: queue.length,
      queue,
      intents: queue
    });
  }
  case 'get_next': {
    const queue = queueFromInput();
    let next = queue.find(function(i) { return i.status === 'in_progress'; });
    if (!next) {
      next = queue.find(function(i) { return i.status === 'pending'; });
      if (next) next.status = 'in_progress';
    }
    if (!next) {
      return JSON.stringify({ success: true, sessionId, intent: null, intentId: null, remaining: 0, queue });
    }
    return JSON.stringify({ success: true, sessionId, intent: next, intentId: next.id, queue });
  }
  case 'mark_done': {
    const queue = queueFromInput();
    const intentId = input.intentId || input.intent_id;
    const current = intentId
      ? queue.find(function(i) { return i.id === intentId; })
      : queue.find(function(i) { return i.status === 'in_progress' || i.status === 'pending'; });

    if (!current) {
      return JSON.stringify({ success: false, sessionId, error: 'intent_not_found', queue });
    }

    current.status = 'done';
    current.result = input.result || null;
    current.error = input.error || null;
    const remaining = queue.filter(function(i) { return i.status !== 'done'; }).length;
    return JSON.stringify({ success: true, sessionId, marked: current.id, remaining, queue });
  }
  case 'count': {
    const queue = queueFromInput();
    const remaining = queue.filter(function(i) { return i.status !== 'done'; }).length;
    return JSON.stringify({ success: true, sessionId, remaining, queue });
  }
  case 'clear': {
    return JSON.stringify({ success: true, sessionId, remaining: 0, queue: [] });
  }
  default:
    return JSON.stringify({ success: false, sessionId, error: 'Unknown action. Use: save, get_next, mark_done, count, clear.', queue: queueFromInput() });
}

