parameters.jsCode:
const input = $('Prepare Chat Input').first().json;
const row = $input.item.json || {};
const hasStoredSession = row.sessionId === input.sessionId;
const validStages = new Set(['welcome', 'auth', 'ready', 'locked']);
const stage = hasStoredSession && validStages.has(row.stage) ? row.stage : 'welcome';
const authAttempts = hasStoredSession ? Number(row.authAttempts || 0) : 0;

return {
  json: {
    sessionId: input.sessionId,
    chatInput: input.chatInput,
    now: input.now,
    stage,
    userName: hasStoredSession ? (row.userName || null) : null,
    userId: hasStoredSession ? (row.userId || null) : null,
    authAttempts: Number.isFinite(authAttempts) ? authAttempts : 0
  }
};
